#include <bits/stdc++.h>
using namespace std;
bool is_prime(int n){
	if(n<2)return false;
	for(int i=2;i*i<=n;i++)
		if(n%i==0)return false;
	return true;
}
int main(){
    int n;
    cin>>n;
	if(is_prime(n) || (n%5 && n%2 && n%3 && n>1)){
        cout<<"Prime\n";
    }else cout<<"Not Prime\n";
    return 0;
}
